INSERT INTO `episodes` (`id`, `serie_id`, `serie_token`, `name`, `title`, `description`, `category`, `duration`, `link`, `download`, `created_at`, `token`, `views`) VALUES
(3038, 2015, '68a5d21a11', 'Night has Come Ep 01', '1. Field Trip', 'When class 2-3 arrives at a retreat center, the rest of the classes are nowhere to be found. Their homeroom teacher goes out to look for the missing classes, and they are left alone in the building. Meanwhile, Yoon-seo and all of her classmates get a message out of the blue. With the rules of the game, each one of them receives a role, and the game begins.', 'Drama', '37', 'https://drive.google.com/file/d/1O4B3Q6yuGncrDeto01rFQDcWv-aM64hh/view?usp=drive_link', '', '2025-09-09 13:04:49', '68c009d1a4', 1),
(3039, 2015, '68a5d21a11', 'Night has Come Ep 02', '2. Figuring Out the Rules', 'As morning dawns, the kids try to figure out what this game is actually about. They realize that they canâ€™t leave the boundary indicated in a white line all around the retreat center. Some kids try going up the trail to see if thereâ€™s a break in the line. However, things only seem to get worse as they start testing the rules and doubting each other more and more.', 'Drama', '36', 'https://drive.google.com/file/d/1uMejPcqwgLuwLMyowqimnalnuTSXR1lM/view?usp=drive_link', '', '2025-09-09 13:06:19', '68c00a2bea', 1),
(3040, 2015, '68a5d21a11', 'Night has Come Ep 03', '3. Rifts Begin to Appear', 'The kids feel guilty and sad about the ones who have died, and this pushes them to drift apart and blame one another. Kyung-jun, the class bully, continues to pick on others and use them to test the rules of the game. Meanwhile, Class President Jun-hee has an idea to refuse to vote for anyone in the game that night.', 'Drama', '31', 'https://drive.google.com/file/d/1n-LQdlYGERvI1SNjMJywukLuZnnFROzs/view?usp=drive_link', '', '2025-09-09 13:07:27', '68c00a6f9d', 3),
(3041, 2015, '68a5d21a11', 'Night has Come Ep 04', '4. A Frenzied Bloodbath', 'As Jun-heeâ€™s plans to refuse to vote backfires, a bloodbath sweeps the assembly hall. The remaining kids are as divided as ever in the aftermath of losing so many kids in one night. Meanwhile, Yoon-seo is suspicious of the visions she keeps having. She decides to scope out the mysterious tunnel that she found.', 'Drama', '35', 'https://drive.google.com/file/d/1jsMRvFKi0qUy11gkfvHUO8XHO8I_pcVV/view?usp=drive_link', '', '2025-09-09 13:08:42', '68c00aba9a', 1),
(3042, 2015, '68a5d21a11', 'Night has Come Ep 05', '5. The Photo Book', 'Woo-ram, the one with the highest votes so far, is about to lose his mind out of fear, and Kyung-jun, the one with the second highest votes, tries to take him down before midnight. Meanwhile, Yoon-seo is stuck on the second floor and finds a photo of the girl she saw in her dream.', 'Drama', '28', 'https://drive.google.com/file/d/1lH61Dk8_u86FyooFteIC5CMBYqBzHwiU/view?usp=drive_link', '', '2025-09-09 13:10:53', '68c00b3d86', 2),
(3043, 2015, '68a5d21a11', 'Night has Come Ep 06', '6. Yoon-seo and Jun-hee', 'Kyung-jun tries to control the rest of the survivors after he catches the second Mafia. He wants to get back at Jun-hee and the rest who voted for him instead of Woo-ram. Furthermore, Kyung-jun and his friends start to suspect Yoon-seo, who knows where to check the security camera footage.', 'Drama', '34', 'https://drive.google.com/file/d/1SDTm6WuEalyl1w4PYu5HuBgV2LiFdQU9/view?usp=drive_link', '', '2025-09-09 13:11:43', '68c00b6fa8', 1),
(3044, 2015, '68a5d21a11', 'Night has Come Ep 07', '7. Find the Host', 'Seung-bin is the next target who gets killed by the Mafia overnight. The survivors find him dead on the floor, and one of his friends is washing the bloody clothes in the toilet. Meanwhile, Yu-jun witnesses Kyung-jun and Jin-ha walking out of the building.', 'Drama', '35', 'https://drive.google.com/file/d/14HDuvGci21AY_BcRQdlaf-UfA0fvetPh/view?usp=drive_link', '', '2025-09-09 13:12:41', '68c00ba991', 1),
(3045, 2015, '68a5d21a11', 'Night has Come Ep 08', '8. No One Can Be Trusted', 'Uncovering yet another fatality, the students find themselves gripped by an encroaching sense of fear, with death looming ever closer. The distinction between Mafia and non-Mafia individuals now appears inconsequential, intensifying their apprehension. As a footprint and a message left on a wall emerge, the list of potential targets is narrowed down to two, heightening the emotional tension just before another vote is about to take place.', 'Drama', '34', 'https://drive.google.com/file/d/1--dEbGWdA4OVjxXDqQ3HTFxsgQtKBaZK/view?usp=drive_link', '', '2025-09-09 13:14:22', '68c00c0e94', 1),
(3046, 2015, '68a5d21a11', 'Night has Come Ep 09', '9. Two Citizens Down', 'The deaths of Jin-ha and Kyung-jun, both innocent Citizens, heighten the students\' sense of entrapment. The prevailing unease about the unreliability of seemingly plausible information forces them to prioritize unmasking the Mafia swiftly for their own survival. Meanwhile, So-mi, for some reason, begins to cast doubt on Na-hee, setting the stage for a sudden turn of events.', 'Drama', '33', 'https://drive.google.com/file/d/1ZuJmNOMoZfYVjYSeEaxe7oVBJBXfj4Vv/view?usp=drive_link', '', '2025-09-09 13:15:38', '68c00c5a09', 1),
(3047, 2015, '68a5d21a11', 'Night has Come Ep 10', '10. One Mafia Down', 'With Na-hee exposing her identity, everyone discovers that So-mi\'s the Mafia, placing Na-hee in danger with her police role now known. Holding herself responsible for her friends\' deaths, Na-hee devises a plan to unveil the Mafia even after her potential death. Although clues surface, they are too ambiguous to conclusively identify the Mafia. Meanwhile, the focus shifts to Mi-na as the next target in the voting process.', 'Drama', '35', 'https://drive.google.com/file/d/1yApHfYMfGsrhNKQL4R8d1BMfRCJM_GkB/view?usp=drive_link', '', '2025-09-09 13:16:27', '68c00c8b53', 1),
(3048, 2015, '68a5d21a11', 'Night has Come Ep 11', '11. The Last Mafia', 'Everyone corners Yeon-woo as the Mafia because he got wounded. He tries to defend himself, but he gets voted in the end. Da-bum feels relieved, and Jun-hee catches that moment. He confronts Da-bum and tells him not to kill Yoon-seo and Jung-won. Yeon-wooâ€™s identity is revealed, and Yoon-seo finds out who the last Mafia is. Meanwhile, Da-bum wants to end the game to avoid being suspected.', 'Drama', '36', 'https://drive.google.com/file/d/1zh1nLs7MPyTDeES0dyUeensAqladsTHp/view?usp=drive_link', '', '2025-09-09 13:17:16', '68c00cbca1', 1),
(3049, 2015, '68a5d21a11', 'Night has Come Ep 12', '12. The End.', 'The Mafia Game nears its conclusion as more classmates are executed. Da-bum continues to threaten the remaining studentsâ€™ lives. Meanwhile, Jung-won faces a dilemma with her life at stake.', 'Drama', '44', 'https://drive.google.com/file/d/1KPVIrkU-7USAhuHa7mDfugSafKoirG0I/view?usp=drive_link', '', '2025-09-09 13:18:29', '68c00d05a3', 3),
(3051, 2014, '68a5d1e29d', 'Squid Game S3 Ep1', '1. Keys and Knives', 'No-eul infiltrates a dangerous operation with a risky plan. A new game is announced: hide-and-seek, where one group holds a key and the other a knife.', 'Action', '52', 'https://drive.google.com/file/d/14NLEN72J7cUMmVRKQvA4Nk49UF4HlIOQ/view?usp=drive_link', '', '2025-09-21 18:34:31', '68d02917cd1b8552952', 5),
(3052, 2014, '68a5d1e29d', 'Squid Game S3 Ep2', '2. The Starry Night', 'The games resume, and Gi-hun fixates on confronting Kang Dae-ho. Meanwhile, Kim Jun-hee faces a sudden crisis that pushes her willpower to its limits.', 'Action', '55', 'https://drive.google.com/file/d/1iD_MGmSLd_30tnAqlg1yDmWdYKQnZ7SM/view?usp=drive_link', '', '2025-09-21 18:34:44', '68d0292470dd5913082', 2),
(3053, 2014, '68a5d1e29d', 'Squid Game S3 Ep3', '3. It\'s Not Your Fault', 'Jun-ho\'s team gets close to finding the island. Jang Geum-ja makes a desperate plea to Gi-hun to help Jun-hee. The VIPs discuss a cruel proposal.', 'Action', '60', 'https://drive.google.com/file/d/1iHZiLKvvXtcd8ZFW_MzYgwGuBVk-RZwL/view?usp=drive_link', '', '2025-09-21 18:34:55', '68d0292f5a128952974', 3),
(3054, 2014, '68a5d1e29d', 'Squid Game S3 Ep4', '4. 222', 'Even as Gi-hun supports Jun-hee amid rising tensions, she must make a pivotal decision. Before the final game, the Front Man gives Gi-hun an ultimatum.', 'Action', '61', 'https://drive.google.com/file/d/1SjYvWI_Q4lEB7lTRvmKJzVWU11PPaAy-/view?usp=drive_link', '', '2025-09-21 18:35:09', '68d0293d56a98295377', 1),
(3055, 2014, '68a5d1e29d', 'Squid Game S3 Ep5', '5. â—‹â–³â–¡', 'No-eul tries to gain the upper hand in negotiations, but her plans backfire. Gi-hun faces a moral crossroads, testing his limits â€” how far will he go?', 'Action', '58', 'https://drive.google.com/file/d/14LQRXfQ1ELxc9VJcjt4om0eLZ9VUMzUO/view?usp=drive_link', '', '2025-09-21 18:35:25', '68d0294d3e7b5869202', 1),
(3056, 2014, '68a5d1e29d', 'Squid Game S3 Ep6', '6. Humans Are...', 'As Jun-ho races to reach the island, tensions peak in the final round. The last players face an impossible situation in the closing minutes of the game.', 'Action', '48', 'https://drive.google.com/file/d/1FPaDjqnxrh_0ha3Zyk6EsmV_cPO1GGYd/view?usp=drive_link', '', '2025-09-21 18:35:40', '68d0295ca6b56373720', 2),
(3057, 2013, '68a5d1b95f', 'Squid Game S2 Ep1', '1. Bread and Lottery', 'A vengeful Gi-hun makes a U-turn at the airport. Later, in his hideout, he intensifies his search for the elusive recruiter who is seeking new players.', 'Action', '40', 'https://drive.google.com/file/d/1YrkzkUKYVrPElUn1oT61Wl0fBRaClD9E/view?usp=drive_link', '', '2025-09-21 18:36:29', '68d0298d7a0ea532222', 2),
(3058, 2013, '68a5d1b95f', 'Squid Game S2 Ep2', '2. Halloween Party', 'Gi-hun finally gets hold of an invitation, marked for Halloween day. In a tense moment facing Jun-ho, they reveal their truths to each other.', 'Action', '43', 'https://drive.google.com/file/d/17XgB0p8K-l2eRJu3Xo3IuQXpN3Zgx0nF/view?usp=drive_link', '', '2025-09-21 18:36:37', '68d0299502e70683954', 2),
(3059, 2013, '68a5d1b95f', 'Squid Game S2 Ep3', '3. 001', 'New players gather for a chance to win 45.6 billion won. After an intense first round, the survivors\' fates hang in the balance â€” down to one final vote.', 'Action', '42', 'https://drive.google.com/file/d/1sJqH_iGNBYRlL446MFFUduqtSMaA01bJ/view?usp=drive_link', '', '2025-09-21 18:36:47', '68d0299f46f8c705328', 1),
(3060, 2013, '68a5d1b95f', 'Squid Game S2 Ep4', '4. Six Legs', 'The players prepare for the next game: a six-legged pentathlon, where each team member must clear a mini-game to survive â€” or face collective elimination.', 'Action', '40', 'https://drive.google.com/file/d/17DKg8ZXsZ8v_BEHF8bcD8xp3PxI9vUwx/view?usp=drive_link', '', '2025-09-21 18:37:52', '68d029e02623d621591', 2),
(3061, 2013, '68a5d1b95f', 'Squid Game S2 Ep5', '5. One More Game', 'Kang No-eul earns enemies for her unruly actions. Nerves fray to the breaking point as the remaining players vote on whether to move to the next round.', 'Action', '42', 'https://drive.google.com/file/d/1NzUM6QhWeWUwUYcB_4hl4UN5iibRHh4L/view?usp=drive_link', '', '2025-09-21 18:37:59', '68d029e7ae764730017', 2),
(3062, 2013, '68a5d1b95f', 'Squid Game S2 Ep6', '6. O ï»¿ X', 'Jun-ho and his team prepare to infiltrate a suspicious island. As monetary stakes and tensions rise, players split into two opposing factions.', 'Action', '40', 'https://drive.google.com/file/d/1gWCUU4HcAQyoaMCacNq6QVlDFRIFiC7d/view?usp=drive_link', '', '2025-09-21 18:38:30', '68d02a0683408577560', 2),
(3063, 2013, '68a5d1b95f', 'Squid Game S2 Ep7', '7. Friend or Foe', 'The remaining players strategize on how to survive the night. Gi-hun proposes a risky plan â€” but he will need trustworthy allies to carry it out.', 'Action', '44', 'https://drive.google.com/file/d/1v73M2RjKM2mM6dFHD8fiMpK_SekKRKoI/view?usp=drive_link', '', '2025-09-21 18:38:43', '68d02a136289a733968', 2),
(3064, 2012, '68a5d187c5', 'Squid Game S1 Ep1', '1. Red Light, Green Light', 'Hoping to win easy money, a broke and desperate Gi-hun agrees to take part in an enigmatic game. Not long into the first round, unforeseen horrors unfold.', 'Action', '40', 'https://drive.google.com/file/d/1Ha_ODpPnWVZbQRkMgrE76eCVLMOEOoJ8/view?usp=drive_link', '', '2025-09-21 18:38:57', '68d02a219b543770001', 1),
(3065, 2012, '68a5d187c5', 'Squid Game S1 Ep2', '2. Hell', 'Split on whether to continue or quit, the group holds a vote. But their realities in the outside world may prove to be just as unforgiving as the game.', 'Action', '42', 'https://drive.google.com/file/d/1sEfR381BbkCi26Me555_AG3qWAqWxKbC/view?usp=drive_link', '', '2025-09-21 18:39:04', '68d02a2880fb4053591', 3),
(3066, 2012, '68a5d187c5', 'Squid Game S1 Ep3', '3. The Man with the Umbrella', 'A few players enter the next round â€” which promises equal doses of sweet and deadly â€” with hidden advantages. Meanwhile, Jun-ho sneaks his way inside.', 'Action', '44', 'https://drive.google.com/file/d/1l3l43sXCEsU8fB4lp66N39eWBc7Uu415/view?usp=drive_link', '', '2025-09-21 18:39:11', '68d02a2fd2bee599917', 1),
(3067, 2012, '68a5d187c5', 'Squid Game S1 Ep4', '4. Stick to the Team', 'As alliances form among the players, no one is safe in the dorm after lights-out. The third game challenges Gi-hun\'s team to think strategically.', 'Action', '40', 'https://drive.google.com/file/d/18CBuCXK2U8_80XC5dkqORuU6gTIhp8KH/view?usp=drive_link', '', '2025-09-21 18:41:11', '68d02aa7e2cf3506802', 1),
(3068, 2012, '68a5d187c5', 'Squid Game S1 Ep5', '5. A Fair World', 'Gi-hun and his team take turns keeping guard through the night. The masked men encounter trouble with their co-conspirators.', 'Action', '41', 'https://drive.google.com/file/d/1uhrt_ciPAyguHvjhUaeqHZCVoahOs3bA/view?usp=drive_link', '', '2025-09-21 18:41:29', '68d02ab97e4d5949373', 3),
(3069, 2012, '68a5d187c5', 'Squid Game S1 Ep6', '6. Gganbu', 'Players pair off for the fourth game. Gi-hun grapples with a moral dilemma, Sang-woo chooses self-preservation and Sae-byeok shares her untold story.', 'Action', '43', 'https://drive.google.com/file/d/1cP35aLME6xq6DIANtol1zTuHjaNv1z97/view?usp=drive_link', '', '2025-09-21 18:41:48', '68d02accecde6216630', 1),
(3070, 2012, '68a5d187c5', 'Squid Game S1 Ep7', '7. VIPS', 'The Masked Leader welcomes VIP guests to the facility for a front-row viewing of the show. In the fifth game, some players crack under pressure.', 'Action', '40', 'https://drive.google.com/file/d/1g1_It9RHkRPikolJ9NDy5qvz_HxMTURH/view?usp=drive_link', '', '2025-09-21 18:42:11', '68d02ae38da3e881892', 2),
(3071, 2012, '68a5d187c5', 'Squid Game S1 Ep8', '8.  Front Man', 'Ahead of the last round, distrust and disgust run deep among the finalists. Jun-ho makes a getaway, determined to expose the game\'s dirty secrets.', 'Action', '42', 'https://drive.google.com/file/d/1vZagi1UVf-zroM7iHtpibj8X1qlBf9qG/view?usp=drive_link', '', '2025-09-21 18:42:37', '68d02afd0e7f8388653', 1),
(3072, 2012, '68a5d187c5', 'Squid Game S1 Ep9', '9. One Lucky Day', 'The final round presents another cruel test â€” but this time, how it ends depends on just one player. The game\'s creator steps out of the shadows.', 'Action', '40', 'https://drive.google.com/file/d/1sbmwSSo6L8VGB446-a0ZKUoBaAImJ-Ar/view?usp=drive_link', '', '2025-09-21 18:43:30', '68d02b328995d101201', 2),
(3073, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep01', '1. Make It Rain', 'In a bid to escape the strip club and Jules\' control, Kimmie applies for a scholarship to the Beauty in Black hair school founded by the Bellarie family.', 'Drama', '40', 'https://drive.google.com/file/d/1fx4G-mUkfHr0zGMGv_-0YKG0_tVR2GQD/preview', '', '2025-09-21 18:46:46', '68d02bf6ce2ee681139', 5),
(3074, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep02', '2. A Dance with Daddy', 'Mallory and Roy try to outmaneuver a chaotic string of events. Kimmie defies orders to help Rain and forges a pact with a secretive, powerful client.', 'Drama', '40', 'https://drive.google.com/file/d/1oCBlRR-H1Qes2AsIy7jTBdiopQdMf-Nc/preview', '', '2025-09-21 18:46:55', '68d02bff8bca2534879', 1),
(3075, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep03', '3. The Aftermath', 'Kimmie\'s choices lead to dangerous consequences. Tension builds between the Bellaries as a furious Norman hunts for answers about the hit and run.', 'Drama', '40', 'https://drive.google.com/file/d/1XKOAxDkc0ASFxPrRt7ERYq9YIn8URK8B/preview', '', '2025-09-21 18:47:09', '68d02c0d20d44623154', 2),
(3076, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep04', '4.  A Family Affair', 'Olivia plays hardball to protect her sons. Angel comes to Kimmie with a daring proposal. As the lawsuit escalates, Mallory contemplates her options.', 'Drama', '40', 'https://drive.google.com/file/d/1Ns7k0ZyuhIl4xZ3_I_Bt8QrqsmWehpd8/preview', '', '2025-09-21 18:47:28', '68d02c20aa23b971714', 2),
(3077, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep05', '5. Unraveling Threads', 'After Angel\'s world gets rocked, Kimmie reconsiders his idea. Jules pulls the family\'s strings. Faced with a difficult choice, Norman\'s suspicions grow.', 'Drama', '40', 'https://drive.google.com/file/d/1sADFS79vwCtF_rpS-Dgm1G27RY21RXkZ/preview', '', '2025-09-21 18:47:40', '68d02c2c79cb2015033', 3),
(3078, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep06', '6. Bang Bang', 'Roy\'s ego reaches new heights as Mallory hunts for his \"other woman.\" Kimmie and Angel look for a way out. Norman\'s grief takes a bloody turn.', 'Drama', '40', 'https://drive.google.com/file/d/1oX1unthWLHrXibWnfie_RCGiI1Ylge4S/preview', '', '2025-09-21 18:47:59', '68d02c3f89dea354550', 1),
(3079, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep07', '7. Even Playing Field', 'Fed up with Roy, Mallory takes matters into her own hands. As Norman digs for the truth, a familiar face comes into focus. Kimmie and Angel make moves.', 'Drama', '40', 'https://drive.google.com/file/d/1h2SlgLSihj9W1ouJwfOMo6VG33j4YN8T/preview', '', '2025-09-21 18:48:08', '68d02c4818c81946114', 1),
(3080, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep08', '8. Killing Karma', 'Schemes and secrets come full circle as Horace connects the dots behind the robbery, Mallory asserts her dominance, and Kimmie hits her breaking point.', 'Drama', '40', 'https://drive.google.com/file/d/1DAY0mXO4kydaNjBVtTE7-zf5e5ovraxk/preview', '', '2025-09-21 18:48:16', '68d02c50891cf463639', 1),
(3081, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep09', '9. Blind Rage', 'Emotions run high as the Bellarie family grieves and schemes. Fueled by vengeance, Kimmie begins a desperate search for her kidnapped sister, Sylvie.', 'Drama', '40', 'https://drive.google.com/file/d/1eHTB_FJU4ACSk44wtUB4W7oGUPy3ODJo/preview', '', '2025-09-21 18:48:28', '68d02c5c423df144339', 1),
(3082, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep10', '10. Power Struggle', 'Kimmie\'s hunt for clues leads to a hostile reunion. Jules does what he does best: clean up the mess. Horace zeroes in on Norman\'s criminal dealings.', 'Drama', '40', 'https://drive.google.com/file/d/1Fw9xqpDontGsuy9CBameyC-Jch_t-Ue7/preview', '', '2025-09-21 18:48:43', '68d02c6be624f353382', 1),
(3083, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep11', '11. Up Against the Wall', 'A worsening lawsuit is the least of Mallory\'s problems as Horace sows chaos. Kimmie takes her search for Sylvie to dangerous new heights.', 'Drama', '40', 'https://drive.google.com/file/d/1AoSN4-TibNMr5C9JavA1jSoVnlFcg8At/preview', '', '2025-09-21 18:48:52', '68d02c74e91df822461', 1),
(3084, 2017, '68d0233730602175861', 'Beauty in Black S1 Ep12', '12. Hot Seat', 'Jules and his men search for Kimmie. Angel plays a precarious game to stay alive. Varney finds himself in the crosshairs of another Bellarie scandal.', 'Drama', '40', 'https://drive.google.com/file/d/1yX0GsEV2tOXNY4m0TIL17L5PCx3FUqN3/preview', '', '2025-09-21 18:49:03', '68d02c7f13576399439', 1),
