(3456, 2060, '6968961cca594038679', 'Hwarang Ep2', '2 Mak Moon\'s Death', 'Dog-Bird receives bad news and Wehwa agrees to form the hwarang as part of Jisoâ€™s grand plan to help ensure Sillaâ€™s future.', 'Drama', '60', 'https://drive.google.com/file/d/1x9vt4cAMOmmu_2SjLo3ePmOXoCHcP_5T/view?usp=drive_link', '', '2026-01-15 09:26:53', '696896bd2677a684986', 10),
(3457, 2060, '6968961cca594038679', 'Hwarang Ep3', '3 Your Brother', 'Wehwa reviews hwarang candidates. Ahnji advises Dog-Bird to pretend to be his son and stay in the capital by taking Seon-uâ€™s name.', 'Drama', '60', 'https://drive.google.com/file/d/1dV5uoTG4cCv_W6y1XH8QwXkg9R9CLhrW/view?usp=drive_link', '', '2026-01-15 09:27:34', '696896e67a995931369', 5),
(3458, 2060, '6968961cca594038679', 'Hwarang Ep4', '4 Become a Hwarang', 'Ahnji faces someone from his past and A-ro teaches Seon-u the ways of the nobility so that he may join the hwarang, but trouble finds Seon-u.', 'Drama', '62', 'https://bysetayico.com/e/x1vk3k0tmbx0', 'https://drive.google.com/file/d/1IvZlTzShq_e7mesiqd_tXNYGBSH8Df1B/view?usp=drive_link', '2026-01-15 16:07:14', '6968f4921c354903647', 11),
(3459, 2059, '696479f248eb6725082', 'Homeland S2 Ep7', '7 The Clearing', 'Reeling from the recent ambush, Carrie and the team struggle to regain control of their operation while Brody and his family attend a fundraiser at a Virginia horse farm. Saul visits Aileen in solitary confinement, hoping she\'ll provide key intelligence on the attack. An anguished Dana pressures Finn to come clean about their hidden crime, but her quest to tell the truth collides with her father\'s secret mission in ways neither could have foreseen.', 'Drama', '53', 'https://bysetayico.com/e/mw1wpekm8zls', 'https://drive.google.com/file/d/1Sj4melZhAZ2CECd-BHt81X1XDADvXsEy/view?usp=drive_link', '2026-01-15 16:28:13', '6968f97d5e352862515', 4),
(3460, 2059, '696479f248eb6725082', 'Homeland S2 Ep8', '8 I\'ll Fly Away', 'He lies for Carrie. He lies for Roya. And he\'s still lying to Jessica. Brody heads towards a serious meltdown as he struggles to keep his complicated alliances clear. Against Quinn\'s orders, Carrie stages a risky intervention to keep Brody in line, forcing both of them to confront their mixed emotions. Meanwhile, Dana turns to an unlikely source for comfort.', 'Drama', '52', 'https://drive.google.com/file/d/1hJ478ZH1FtE6mxny8mvJ0_-3d40ocqjs/view?usp=drive_link', '', '2026-01-15 16:28:59', '6968f9ab63379899395', 3),
(3461, 2059, '696479f248eb6725082', 'Homeland S2 Ep9', '9 Two Hats', 'Brody makes a necessary phone call. Saul teams up with Virgil and Max to dig up some information on one of their own. Carrie finds herself preparing for the most important meeting of her career.', 'Drama', '49', 'https://drive.google.com/file/d/15kbBknsslx3aDjHsojjnu4tXeVrJPsq6/view?usp=drive_link', '', '2026-01-15 16:29:31', '6968f9cbeef3f848377', 2),
(3462, 2059, '696479f248eb6725082', 'Homeland S2 Ep10', '10 Broken Hearts', 'Saul catches up with an old friend and discovers evidence of covert activities by Estes. Brody and Vice President Walden find themselves at odds over the future of their political relationship, while Dana and Finn come to terms with their own differences.', 'Drama', '49', 'https://drive.google.com/file/d/1CAN13NB4JYXHoQoT1X8qy0jJj5jlLBBS/view?usp=drive_link', '', '2026-01-15 16:30:20', '6968f9fccd684530208', 3),
(3463, 2059, '696479f248eb6725082', 'Homeland S2 Ep11', '11 In Memoriam', 'Dangerously close to exhaustion, Carrie continues her hunt for Nazir and begins to suspect there is a mole in the CIA. Roya reveals her true colours under interrogation and Saul finds himself fighting to save his career under unexpected circumstances. Meanwhile, the Brodys struggle to maintain anything close to a state of sanity.', 'Drama', '52', 'https://bysetayico.com/e/ivrh20ehiuql', 'https://drive.google.com/file/d/1PPO24xzpkDBsCXOekaByJhf33LZ7HGt6/view?usp=drive_link', '2026-01-16 22:41:03', '696aa25f6af3f549845', 2),
(3464, 2059, '696479f248eb6725082', 'Homeland S2 Ep12', '12 The Choice', 'Carrie is faced with a pivotal decision, while Brody meets with Faber to contemplate the future of the family. Meanwhile, Saul undertakes a secret assignment; and Quinn has a decision to make that may prove to be a game-changer.', 'Drama', '66', 'https://bysetayico.com/e/8csole6vfa59', 'https://drive.google.com/file/d/1blBJ0WRbNdUyjS3po_cYhrCNt6P8UNp-/view?usp=drive_link', '2026-01-16 22:42:06', '696aa29e13298204554', 2),
