(3578, 2071, '6984efdc582b7032279', 'Always a Witch Ep1', '1 A Leap in Time', 'While being burned at the stake in 1646 Cartagena, Carmen -- a witch and slave -- time travels to the future to save both herself and the man she loves.', 'Drama', '42', 'https://bysetayico.com/e/at2bqfgm4lr7', 'https://drive.google.com/file/d/1OeemoMgdfkz9Xg6ciw5f0OFwaw8rarf6/view?usp=drive_link', '2026-02-05 21:32:35', '6984f05320b82457929', 13),
(3579, 2071, '6984efdc582b7032279', 'Always a Witch Ep2', '2 A University Witch', 'Suspicious of Alicia, Carmen follows her to a college class, where she tries to fit in as a student in a strange world of cellphones and social media.', 'Drama', '44', 'https://bysetayico.com/e/gqp3cg3z0996', 'https://drive.google.com/file/d/1Touz8PyhGBOoPUegOHebPn7mJ3ikfQU3/view?usp=drive_link', '2026-02-05 21:33:16', '6984f07c5c621423359', 9),
(3580, 2071, '6984efdc582b7032279', 'Always a Witch Ep3', '3 Ouija', 'Carmen tries to reach Aldemar via a Ouija board. Instead, a ghost who can\'t remember who he is appears. In the past, CristÃ³bal asks Aldemar for help.', 'Drama', '39', 'https://bysetayico.com/e/xg2upwczgi85', 'https://drive.google.com/file/d/1vpxjeceES3bsH2WJjDQ-npInULQWMVb3/view?usp=drive_link', '2026-02-05 21:35:24', '6984f0fc44036222574', 8),
(3581, 2071, '6984efdc582b7032279', 'Always a Witch Ep4', '4 Stolen Shadow, Witch Forgotten', 'A preventive step is taken to protect Carmen from Lucien, but it ends up affecting her memory, personality and maybe even her sanity.', 'Drama', '35', 'https://bysetayico.com/e/wiargh98c4nr', 'https://drive.google.com/file/d/1LQ45aJ5uqjZ29wsR2Uq6Q5UozZwbBI8L/view?usp=drive_link', '2026-02-05 21:36:07', '6984f1274c211368426', 6),
(3582, 2071, '6984efdc582b7032279', 'Always a Witch Ep5', '5 The Festival of Candela', 'While her friends look for her, a lost and disoriented Carmen runs into someone from her past. Jhony Ki discovers how to communicate with CristÃ³bal.', 'Drama', '37', 'https://bysetayico.com/e/zkiqz1f4yk5f', 'https://drive.google.com/file/d/1THOPjxABLWjnZijkbNSOAg_xJM86KZAe/view?usp=drive_link', '2026-02-05 21:36:52', '6984f154de86a255755', 6),
(3583, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep1', '1 Namak Ka Paani', 'As the dead body of a RAW agent washes ashore in Mumbai, Commander Karan Saxena takes charge. Nearby, something sinister brews as ISI agent Javed activates the sleeper cells.', 'Action', '24', 'https://bysetayico.com/e/ffvclkkmqkqa', 'https://drive.google.com/file/d/1Y22r_P9AuwG65vEZlCPSINYgYa3R8wE2/view?usp=drive_link', '2026-02-07 09:46:14', '6986edc607f9f367708', 3),
(3584, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep2', '2 Talaash', 'ACP Rachana Mhatre must assist Karan as the team probes the presence of ISI agent Javed in Mumbai. A bigger threat looms with the news of a missing fisherman!', 'Action', '23', 'https://bysetayico.com/e/65jtfjap9tcq', 'https://drive.google.com/file/d/1QXMwgaruD5dTjoPCsx2ZdZFGQt95-mmd/view?usp=drive_link', '2026-02-07 09:46:53', '6986eded8dc65073995', 2),
(3585, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep3', '3 Tere Sheher Mein!', 'A message from ISI agent Javed spurs Karan and the team into action. Getting their hands on a voice recording, Rachana and Karan uncover a shocking intel.', 'Action', '23', 'https://bysetayico.com/e/9ljjrzch18hs', 'https://drive.google.com/file/d/16jc0QY6LOfrSygLxs3J9qNidzNRrqSl7/view?usp=drive_link', '2026-02-07 09:47:38', '6986ee1a3dbed299720', 3),
(3586, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep4', '4 Sheh Aur Maat', 'Flashbacks reveal Colonel Nasirâ€™s deep-seated vendetta against India. Ready for a fightback, Karan and Rachana scour the city to defuse the impending attack.', 'Action', '23', 'https://bysetayico.com/e/mgxjq8fje60l', 'https://drive.google.com/file/d/19wFGNEAsGDhLa4dOIRxrJ7FdJiDlkdkv/view?usp=drive_link', '2026-02-07 09:48:10', '6986ee3a0763e186147', 4),
(3587, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep5', '5 Kaun Hai Gaddaar?', 'A disturbing scene unfolds as Rachana and Karan find the hideout of sleeper cells. While Nasir sets an alternate plan in motion, Karan suspects a possible mole in the force.', 'Action', '19', 'https://bysetayico.com/e/qoag2wqpu262', 'https://drive.google.com/file/d/1Os78XO2CVxrV836rTAaorGlqEaHqmIMJ/view?usp=drive_link', '2026-02-07 09:48:56', '6986ee68c283b224206', 1),
(3588, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep6', '6 Haryana Mein Kya Hai?', 'With the force hot on his trail, Nasir flies to Haryana to execute his alternate plan. Back in Mumbai, Rachana tracks down the assailant who attacked RAW agent Sameer.', 'Action', '22', 'https://bysetayico.com/e/cidk71774ei0', 'https://drive.google.com/file/d/1TdW0aV5C8pSNvnFmihdmDcV7LaEUJgs_/view?usp=drive_link', '2026-02-07 09:49:40', '6986ee9434a99170563', 1),
(3589, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep7', '7 Khet, Hookah, Aur Khat', 'With the help of his informant, Karan mobilises his network in Haryana to track down Nasir. Meanwhile, Rachana plans a covert move to find Javed.', 'Action', '22', 'https://bysetayico.com/e/0946ptmndcyd', 'https://drive.google.com/file/d/1jVHA2KQeSPE-rJwsMFThEHxTw5wmCwaA/view?usp=drive_link', '2026-02-07 09:50:36', '6986eecc78ca0012834', 1),
(3590, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep8', '8 Mayajaal', 'Karan leads a covert mission to ambush Nasir but faces a major setback! With pressure mounting, Rachana launches a manhunt to find Javed.', 'Action', '22', 'https://bysetayico.com/e/e6em33rshrqf', 'https://drive.google.com/file/d/1EKesnrZtOWs4OdV7X23GHstP5J0C124G/view?usp=drive_link', '2026-02-07 09:51:19', '6986eef7f3b11119286', 1);
