(3591, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep9', '9 Dagabaaz', 'Karan starts connecting the dots to find the mole in the police force. Wrestling with a personal issue, Rachana closes in on the traitor. And she makes a choice!', 'Action', '19', 'https://bysetayico.com/e/wt3go9ojab9u', 'https://drive.google.com/file/d/16G7WtxEGC3WVb5icOU8TDXGEJezpuaT-/view?usp=drive_link', '2026-02-07 09:52:01', '6986ef21ed9f4983929', 1),
(3592, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep10', '10 Ab Hoga Palatvaar!', 'The mole within the police force is identified! Tension heightens as Nasir narrates his plan on a call with Karan. With rising threats, the team braces for a fightback.', 'Action', '20', 'https://bysetayico.com/e/28255b6w3y3y', 'https://drive.google.com/file/d/1SwoxFEtfQaMgMTRK-afJpmxOlR1kmjCv/view?usp=drive_link', '2026-02-07 09:52:51', '6986ef53ef56b482367', 2),
(3593, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep11', '11 Ek Saanp, Ek Sher', 'New intel about an ISI-hired assassin comes to light as Karan interrogates the mole, Inspector Amar. Meanwhile, constable Patil comes dangerously close to Nasir.', 'Action', '24', 'https://bysetayico.com/e/bbzxzvrkn8xh', 'https://drive.google.com/file/d/19TIQ3zb6cPa4qpySQZl32JnVuMeyGmDq/view?usp=drive_link', '2026-02-07 09:53:32', '6986ef7c8544b684047', 1),
(3594, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep12', '12 Ranneeti', 'The tragic death of constable Patil lifts the lid on a hideout! Karan and the team prepare to strike the hiding foes but get caught in a deadly crossfire.', 'Action', '21', 'https://bysetayico.com/e/j58dncxhnim7', 'https://drive.google.com/file/d/1cIdC7mTjwl24vRB4Hf428W22b5soMTft/view?usp=drive_link', '2026-02-07 09:54:12', '6986efa459af8522648', 1),
(3595, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep13', '13 Plan B', 'The deadly assassin Alexei springs into action, targeting Karan and the team. Solidifying an alternate plan, Karan readies to pounce back!', 'Action', '19', 'https://bysetayico.com/e/1mpj33wwlyyv', 'https://drive.google.com/file/d/1s_6sI_7qedVe_7jxPVMupA3Lzyjw9IE-/view?usp=drive_link', '2026-02-07 09:54:57', '6986efd1e884b580488', 1),
(3596, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep14', '14 Veergati', 'On the verge of a risky mission, Karan reflects on his journey as the commander. While the RAW team gains the upper hand, Nasir forges an alternate plan - doomsday!', 'Action', '26', 'https://bysetayico.com/e/0zqvgtk2jzub', 'https://drive.google.com/file/d/1rJjsBEhbqIutc1KHL4SsVfwMVbJBIv5U/view?usp=drive_link', '2026-02-07 09:55:49', '6986f0056616b640346', 1),
(3597, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep15', '15 Kaun Apna, Kaun Paraya', 'The notes from Alexei lead Karan to Nasirâ€™s secret hideout. But his plan to counterattack takes a dangerous turn as Nasirâ€™s covert ally steps out of the shadows.', 'Action', '18', 'https://bysetayico.com/e/a3qeg5dzpyyq', 'https://drive.google.com/file/d/10RXtWqGarBoUMhpTktwlIyjmvom7LRpk/view?usp=drive_link', '2026-02-07 09:56:43', '6986f03ba120c767485', 2),
(3598, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep16', '16 Woh Amar Hai!', 'Tension heightens as the protestors in Haryana lead a search party to find Sher Singh. Meanwhile, a journalist tries to unveil the mystery around Karanâ€™s death.', 'Action', '20', 'https://bysetayico.com/e/6x55sxlpmy9h', 'https://drive.google.com/file/d/1--Ei7HnABHlettM6UC0rBEOmuveAnsXi/view?usp=drive_link', '2026-02-07 09:57:23', '6986f0636dcd6788823', 1),
(3599, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep17', '17 Tohfa', '\r\n\r\nRachanaâ€™s arrest sparks chaos! Flashbacks reveal the making of a master plan. A new intel on Nasirâ€™s secret ally stirs doubts about loyalty and treason within the force.', 'Action', '19', 'https://bysetayico.com/e/8g30j0pkv7ga', 'https://drive.google.com/file/d/1-gEI7SlHNP4k96PbHu_BMqbbp8vjIT-e/view?usp=drive_link', '2026-02-07 09:58:14', '6986f0963dce4504256', 1),
(3600, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep18', '18 Deshdrohi', 'A new danger looms as Nasir puts his ultimate pawn ACP Vinay Awasthi into action. While a deadly explosive is being readied, Karan and Rachana must race against the time.', 'Action', '17', 'https://bysetayico.com/e/f8et05r1xx4h', 'https://drive.google.com/file/d/1fpdEZGczYaVVZU7X6V3gAACBw58c4uuZ/view?usp=drive_link', '2026-02-07 09:59:02', '6986f0c60b679940771', 2),
(3601, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep19', '19 Tick, Tick...Boom!', 'Pressure mounts as the protestors brace for a confrontation with Karan. Vying for the upper hand, Nasir and Javed set the Black Day plan in motion.', 'Action', '21', 'https://bysetayico.com/e/i0d3j7dyxs5e', 'https://drive.google.com/file/d/1b2k1_Eh8-UFW7an3Kp3DPYph5gl2FAmf/view?usp=drive_link', '2026-02-07 09:59:48', '6986f0f48a3af139272', 1),
(3602, 2072, '6986ecc8a30cc634315', 'Commander Karan Saxena Ep20', '20 Taandav!  [Season Finale]', 'Karan is faced with impossible odds as Nasir and his allies are all set for the final strike. Amid the pandemonium, the forces must retaliate to bring down the enemies.', 'Action', '20', 'https://bysetayico.com/e/36uwakute2ao', 'https://drive.google.com/file/d/1P48fq_SqbPGUgahmNhFe3wzgxQCe1C23/view?usp=drive_link', '2026-02-07 10:00:46', '6986f12eed7a9757187', 2),
(3603, 2071, '6984efdc582b7032279', 'Always a Witch Ep6', '6 The Ritual of Forgetting', 'A text message on LeÃ³n\'s phone upsets Mayte. Carmen\'s heartbreak makes her lose control of her magic powers. CristÃ³bal secretly meets with Aldemar.', 'Drama', '37', 'https://bysetayico.com/e/936kp1hp9i84', 'https://drive.google.com/file/d/1WCh3TecXHMCgHDRfZZ1Jlj6UDLgDFiLU/view?usp=drive_link', '2026-02-09 09:53:57', '698992957f288980191', 4),
(3604, 2071, '6984efdc582b7032279', 'Always a Witch Ep7', '7 Lucien', 'With her friends\' help, Carmen tries to break the spell cast upon Mayte by rekindling LeÃ³n\'s ardor. Later, she learns Lucien\'s alternate identity.', 'Drama', '37', 'https://bysetayico.com/e/vxtpnula4bpt', 'https://drive.google.com/file/d/11iVJJq9Rn0vIfZYWtMujTbhbc7kZEv8z/view?usp=drive_link', '2026-02-09 09:54:57', '698992d1b25ac004220', 3),
(3605, 2071, '6984efdc582b7032279', 'Always a Witch Ep8', '8 1646', 'After Carmen returns to CristÃ³bal in 1646, Aldemar travels to the present and confronts Lucien. Mayte struggles to recall what happened after her date.', 'Drama', '40', 'https://bysetayico.com/e/xfnxscfyrrs0', 'https://drive.google.com/file/d/129pd1OAY1HEy7yszURULskIiTp10ooJ3/view?usp=drive_link', '2026-02-09 09:55:54', '6989930a2e293941953', 3),
(3606, 2071, '6984efdc582b7032279', 'Always a Witch Ep9', '9 The Time Portal', 'One of Carmen\'s friends travels to the 1600s to bring her back, just as she gets caught planning a slave rebellion. Esteban faces a difficult decision.', 'Drama', '37', 'https://bysetayico.com/e/gx5m8nrf1d3v', 'https://drive.google.com/file/d/1BbrxnCSuikKT1H98XM5pJ4EgUV0Y8jzt/view?usp=drive_link', '2026-02-09 09:56:43', '6989933b9a219915680', 3),
(3607, 2071, '6984efdc582b7032279', 'Always a Witch Finale Ep10', '10 The Final Trip  [Season Finale]', 'In a final showdown, Carmen attempts to lure the Fire Killer into a trap, but an ambush awaits her. Jhony Ki receives a rare and precious gift.', 'Drama', '38', 'https://bysetayico.com/e/vwmo9b40rw6i', 'https://drive.google.com/file/d/1bTqr_KZSt1S2kBclK1MRLQRmJvVUa16V/view?usp=drive_link', '2026-02-09 09:58:04', '6989938c3159f452960', 5),
