(3612, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep1', '1 Episode 1', 'Inside Lee Byeong-chan\'s science lab, a student incurs a seemingly harmless bite. Shortly after, a fast-spreading outbreak soaks the school in blood.', 'Action', '69', 'https://bysetayico.com/e/ova8xeo9u68o', 'https://drive.google.com/file/d/15d1qGOQySnoMrOfVFtF2VQ3fKvFtjls-/view?usp=drive_link', '2026-02-14 09:09:41', '69901fb554c37731439', 3),
(3613, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep2', '2 Episode 2', 'The infected multiply in droves. Scrambling for their lives, Nam On-jo and Lee Cheong-san find safety with others inside a classroom â€” but not for long.', 'Action', '72', 'https://bysetayico.com/e/ttyyjyvwmadw', 'https://drive.google.com/file/d/1CsHfw0lfFcF36nI71zjv5qEO1L_5Hifc/view?usp=drive_link', '2026-02-14 09:10:27', '69901fe306ca4124781', 2),
(3614, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep3', '3 Episode 3', 'When one of the group is scratched while fighting a zombie, Lee Na-yeon demands they kick him out. Outside, the virus swallows up the city.', 'Action', '63', 'https://bysetayico.com/e/dc4odk34529a', 'https://drive.google.com/file/d/1ztFMier6Kz2LmXGm2fu0o92HZkurwlvh/view?usp=drive_link', '2026-02-14 09:11:16', '69902014608b2131982', 2),
(3615, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep4', '4 Episode 4', 'In need of a cellphone, two students take a risky journey to the teachers\' office. Byeong-chan passes on critical information to Detective Song Jae-ik.', 'Action', '75', 'https://bysetayico.com/e/82wrdoaheez2', 'https://drive.google.com/file/d/1koyHIwGI60E2CUy07JOceaQIIODSmYVt/view?usp=drive_link', '2026-02-14 09:12:00', '69902040380c2190604', 3),
(3616, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep5', '5 Episode 5', 'Martial law is imposed on the city. When Cheong-san is separated from the rest of the group, On-jo leads a mission to use a drone to locate him.', 'Action', '58', 'https://bysetayico.com/e/vu8i6oti9lnp', 'https://drive.google.com/file/d/1_4X9tdbOhUEBcM8Rb2PvGHcCySTz5phH/view?usp=drive_link', '2026-02-14 09:12:50', '699020728a9df584915', 1),
(3617, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep6', '6 Episode 6', 'The group clears a path to Cheong-san using sound to draw away zombies, but a new type of threat surfaces. Nam So-ju breaks out of the quarantine camp.', 'Action', '70', 'https://bysetayico.com/e/92e8c88o9ze7', 'https://drive.google.com/file/d/1hYirDUXYY4f8297NghJ0wBx_KUOODo5X/view?usp=drive_link', '2026-02-14 09:13:32', '6990209c9b9dd747379', 1),
(3618, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep7', '7 Episode 7', 'To make it out of the music room and onto the roof, the students put into action their most perilous plan yet. Elsewhere, Jae-ik comes across a setback.', 'Action', '61', 'https://bysetayico.com/e/erfuhh9mee69', 'https://drive.google.com/file/d/1KftKsFIm3YUigwZ-NTB642OWdU47Vig8/view?usp=drive_link', '2026-02-14 09:14:28', '699020d4d3f71205573', 1),
(3619, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep8', '8 Episode 8', 'Jae-ik and his crew run into a student from the school. Na-yeon works up the courage to face her peers. The group shares confessions around a fire.', 'Action', '64', 'https://bysetayico.com/e/e90b624v91qj', 'https://drive.google.com/file/d/16tRxGCws7gime-3OPPJ_Hhz0-3-W89Bo/view?usp=drive_link', '2026-02-14 09:15:11', '699020ff5a514185851', 1),
(3620, 2074, '69901f5ee0313071880', 'All of Us Are Dead Ep9', '9 Episode 9', 'A disturbance at the camp shifts the military\'s understanding of the virus. A thunderstorm provides cover as the group agrees to keep on moving.', 'Action', '54', 'https://bysetayico.com/e/tln6hcujuyf6', 'https://drive.google.com/file/d/1apH_PLJQgyHOShWHpCjD17pk_QJyPhK3/view?usp=drive_link', '2026-02-14 09:15:58', '6990212e38468303663', 1),
