(3701, 2075, '6990237a5f9e6862024', 'The Pendragon Cycle Ep4', '4 The King of Maridunum', 'As Britain bleeds, Merlin must forge unity from chaosâ€”while darkness moves behind kings and blades.', 'Sci-Fi', '64', 'https://bysetayico.com/e/h9capjf0ryml', 'https://drive.google.com/file/d/1wEmSV8LEk_n_8HF0SPef3FHhPvEZF036/view?usp=drive_link', '2026-02-28 12:40:14', '69a2c60e6e5aa069283', 3),
(3702, 2075, '6990237a5f9e6862024', 'The Pendragon Cycle Ep5', '5 The Price of Failure', 'War brews, loyalties splinter, and Merlin\'s past eruptsâ€”threatening to destroy the fragile future he fights for.', 'Sci-Fi', '69', 'https://bysetayico.com/e/yi3u2i32hz19', 'https://drive.google.com/file/d/1zlqXcGFwwYrYg4QFt80-o4CLZP5Po1aU/view?usp=drive_link', '2026-02-28 12:41:14', '69a2c64a717d2034605', 2),
(3703, 2086, '69a34b9e62736088876', 'Traveler Ep1', '1 Pilot', 'Good friends Jay, Tyler, and Will have done just about everything together for the past two years, but being together ends today. Jay and Tyler become prime suspects in a terrorist bombing at a famous New York City museum after rollerblading through it as a prank.', 'Drama', '46', 'https://bysetayico.com/e/i8kdmkhhejjz', 'https://drive.google.com/file/d/1ZOo5WuCSsA83wqc8t4ZBeodLpEuxWX9F/view?usp=drive_link', '2026-02-28 22:11:35', '69a34bf7f2075363032', 2),
(3704, 2086, '69a34b9e62736088876', 'Traveler Ep2', '2 The Retreat', 'Jay and Tyler arrive at Carlton Fog\'s safe house, but they question the loyalty of a power broker who has been assigned by Fog to help them. Meanwhile, FBI agents question Jay\'s girlfriend, Kim.', 'Drama', '45', 'https://bysetayico.com/e/far9hckbabd4', 'https://drive.google.com/file/d/1Ed2gtjZnvDuzkcFKWpqfWpeuNxUvGdqw/view?usp=drive_link', '2026-02-28 22:12:16', '69a34c20214fb615646', 1),
(3705, 2086, '69a34b9e62736088876', 'Traveler Ep3', '3 New Haven', 'Jay and Tyler return to New Haven in an attempt to locate items that may prove their innocence. Meanwhile, Carlton Fog holds a press conference in regards to his choice to shelter his son.', 'Drama', '44', 'https://bysetayico.com/e/6hfk1dl0tnc1', 'https://drive.google.com/file/d/1dPyKAOwOb12mPoI6N9EaU3Gh0Kw6H2FF/view?usp=drive_link', '2026-02-28 22:12:55', '69a34c47f075c048148', 2),
(3706, 2086, '69a34b9e62736088876', 'Traveler Ep4', '4 The Out', 'Jay and Tyler head to Deer Harbor, Maine, Will\'s hometown. The FBI discovers new evidence regarding the museum bombing. Meanwhile, Jay and Tyler talk to a woman who had planned to leave her hometown with Will after the bombing.', 'Drama', '50', 'https://bysetayico.com/e/n6mhp45o048d', 'https://drive.google.com/file/d/1m1WMOMXpOhyxDYWnBHGiWPhY-Y7VAzz_/view?usp=drive_link', '2026-02-28 22:13:36', '69a34c70f0630182508', 1),
(3707, 2086, '69a34b9e62736088876', 'Traveler Ep5', '5 The Tells', 'Jay and Tyler\'s search leads them to Boston where a security box is uncovered containing aliases Will used and evidence about the bombing. After being captured by his bosses, Will Traveler undergoes interrogation and reveals what happened on the day of the Drexler bombing. A key arrest made by the FBI shows that the Drexler conspiracy goes far beyond what they had initially imagined.', 'Drama', '50', 'https://bysetayico.com/e/sybgqdksvaze', 'https://drive.google.com/file/d/1RXJ5cqmInx241w63Wp9pm_RcVbYD__zd/view?usp=drive_link', '2026-02-28 22:14:21', '69a34c9d0e6e4509054', 1),
(3708, 2087, '69a34f8fbf5a9769770', 'Fate: The Winx Saga Ep1', '1 To the Waters and the Wild', 'In hopes of mastering her magic, Bloom begins her studies at Alfea â€” and crosses paths with her curious classmates. Meanwhile, a secret comes to light.', 'Sci-Fi', '58', 'https://bysetayico.com/e/uvj9jqa2vhc7', 'https://drive.google.com/file/d/1AuwjL0yJA_no0le0An_2jbz4MyO82NNm/view?usp=drive_link', '2026-02-28 22:27:50', '69a34fc6a5f2d489935', 2),
(3709, 2087, '69a34f8fbf5a9769770', 'Fate: The Winx Saga Ep2', '2 No Strangers Here', 'A new day dawns as the students explore their powersâ€¦ and feelings. Bloom and Stella team up for a mission. The Burned Oneâ€™s reign of terror evolves.', 'Sci-Fi', '51', 'https://bysetayico.com/e/kn7jx428xcte', 'https://drive.google.com/file/d/1w2X51RnIHruX6K5KmkuzVKuBLARnKQAR/view?usp=drive_link', '2026-02-28 22:28:27', '69a34febe330b696302', 2),
(3710, 2087, '69a34f8fbf5a9769770', 'Fate: The Winx Saga Ep3', '3 Heavy Mortal Hopes', 'Past meets present as Bloom explores a pivotal memory. Meanwhile, Aisha struggles with her studies, Silva shares a secret and a school party takes shape.', 'Sci-Fi', '56', 'https://bysetayico.com/e/5h5201t6vkgq', 'https://drive.google.com/file/d/1jMas-U9KlRZvR3Z_t2ih-3h-olQ55mbu/view?usp=drive_link', '2026-02-28 22:29:03', '69a3500fb9236926277', 1),
(3711, 2087, '69a34f8fbf5a9769770', 'Fate: The Winx Saga Ep4', '4 Some Wrecked Angel', 'Bloom continues her search for answers with Sky. Beatrix works to conceal her crime. A special guest visits Alfea â€” and leaves Stella feeling conflicted.', 'Sci-Fi', '54', 'https://bysetayico.com/e/ykplp2ndrqwa', 'https://drive.google.com/file/d/1DB_3aW7wYQ6v9FUUWK_byRQFH2lB9394/view?usp=drive_link', '2026-02-28 22:29:41', '69a35035a51d7484619', 1),
(3712, 2087, '69a34f8fbf5a9769770', 'Fate: The Winx Saga Ep5', '5 Wither Into The Truth', 'In order to reconnect with Beatrix, Bloom seeks the help of a fellow student. Sky opens up about his past. Ms. Dowling shares more of her story.', 'Sci-Fi', '55', 'https://bysetayico.com/e/2e2qfvqu8s0k', 'https://drive.google.com/file/d/1V7cc3YMHkdFEsBcS7apZ_JEzN9iPGrVX/view?usp=drive_link', '2026-02-28 22:30:16', '69a350584db45216400', 0),
(3713, 2087, '69a34f8fbf5a9769770', 'Fate: The Winx Saga Ep6', '6 A Fanatic Heart  [Season Finale]', 'As the Alfeans fight for survival, the truth about Bloomâ€™s destiny is revealed. Can she help defeat the Burned Ones â€” or will evil outperform magic?', 'Sci-Fi', '60', 'https://bysetayico.com/e/3g2utna27i9s', 'https://drive.google.com/file/d/1s-4Q3Ef88OEAXdfhm2dIKqSTo047uYwy/view?usp=drive_link', '2026-02-28 22:31:04', '69a35088655de405294', 1),
