(3829, 2101, '69c76d0fb349d213989', 'Cashero Ep1', '1 Episode 1', 'Unable to afford a place with Kim Min-suk, Kang Sang-ung visits his father â€” who grants him a power that will test both his morals and his bank account.', 'Action', '64', 'https://bysetayico.com/e/17cz6qv7was5', 'https://drive.google.com/file/d/1C4aXIko-kAkslJAhH_I8dO6Axdc-8X9q/view?usp=drive_link', '2026-03-28 07:55:43', '69c76d5f4adcc893160', 15),
