(3832, 2102, '69cd03e0850bc908347', 'Last Samurai Standing Ep2', '2 Awakening', 'Kyojin, a former ninja, proposes an alliance with Shujiro and Futaba. Meanwhile, a high-ranking government official fears a potential samurai uprising.', 'Action', '52', 'https://bysetayico.com/e/zk8qgsit4ap8', 'https://drive.google.com/file/d/1EuzOYIbJ4KRvGvmyQF7o6sR-gA5UDi39/view?usp=drive_link', '2026-04-01 13:47:15', '69cd05c373225599066', 6),
(3833, 2094, '69a9bdd9352c1385676', 'Stranger Things S3 Ep3', '3 Chapter Three: The Case of the Missing Lifeguard', 'With El and Max looking for Billy, Will declares a day without girls. Steve and Dustin go on a stakeout, and Joyce and Hopper return to Hawkins Lab.', 'Horror', '48', 'https://bysetayico.com/e/wzezybhaas6o', 'https://drive.google.com/file/d/1i_1OXZYjmTgIrPZg0PKx1GRWznxnPllt/view?usp=drive_link', '2026-04-03 09:43:26', '69cf6f9ea249c377761', 1),
