(3837, 2094, '69a9bdd9352c1385676', 'Stranger Things S3 Ep7', '7 Chapter Seven: The Bite', 'With time running out -- and an assassin close behind -- Hopper\'s crew races back to Hawkins, where El and the kids are preparing for war.', 'Horror', '55', 'https://bysetayico.com/e/wmio4ughhnoc', 'https://drive.google.com/file/d/1M-gClcIQl8dR3OwOsBgMO-AUMLtvWK55/view?usp=drive_link', '2026-04-03 09:46:15', '69cf7047859f2139455', 1),
