(3839, 2018, '68d0276ae8def191374', 'Beauty in Black S2 Ep13', '13 Boom!', 'Kimmie\'s mandate puts Charles and Roy at risk. Rain takes on an ambitious business venture. A shocking revelation upends Norman\'s world.', 'Drama', '45', 'https://bysetayico.com/e/bheew1pz0h3m', 'https://drive.google.com/file/d/1x1WAf-HBjlFV1ko7DmzmS7MDcusXSq4P/view?usp=drive_link', '2026-04-04 08:41:22', '69d0b2927d1c3959938', 7),
(3840, 2018, '68d0276ae8def191374', 'Beauty in Black S2 Ep14', '14 Your Turn Is Coming', 'Kimmie cautiously weighs an unlikely alliance. Jules menaces a suspect who knows more than she\'s saying. A stakeout turns into a white-knuckle pursuit.', 'Drama', '43', 'https://bysetayico.com/e/rhmeis7qbu4r', 'https://drive.google.com/file/d/1nJrxOLOjqRQvQsS92P9SxoFDIjfVMneU/view?usp=drive_link', '2026-04-04 08:42:16', '69d0b2c8bc205121967', 8),
(3841, 2103, '69d0b394734db534669', 'Taken Ep1', '1 Pilot', 'The murder of Bryan Mills\' sister launches him into a dangerous mission for revenge against cartel boss Carlos Mejia. A secret US intelligence agency, led by Christina Hart, covertly uses Bryan as bait to capture Mejia, and in the end recruits Bryan to become a part of their team.', 'Action', '54', 'https://bysetayico.com/e/fja1q4mendrs', 'https://drive.google.com/file/d/1Tspj2zOlljAYXNrZVGcwm73YFrYT9zGp/view?usp=drive_link', '2026-04-04 08:50:01', '69d0b49992040277927', 10),
(3842, 2103, '69d0b394734db534669', 'Taken Ep2', '2 Ready', 'Bryan gets his first chance in the field but the mission goes bust, resulting in a tragic death. The team uncovers a group of government officials skimming off of refugee funds, which also leads Christina to reconnect with a long lost love. Meanwhile, Asha shows up unexpectedly at Bryan\'s doorstep.', 'Action', '46', 'https://bysetayico.com/e/26lp7ga03ndf', 'https://drive.google.com/file/d/1k6ldt6ndKK2K1gOvyjb7q8ebWPMcMYdl/view?usp=drive_link', '2026-04-04 08:50:49', '69d0b4c9b62b5110532', 4),
(3843, 2103, '69d0b394734db534669', 'Taken Ep3', '3 Off Side', 'Bryan and team search for a suspected terrorist who has been taken, leading them to uncover a deeper plot within their own government. Christina receives troubling news and turns to Harry for support. Asha expresses her concern over Bryan\'s fixation with Mejia.', 'Action', '47', 'https://bysetayico.com/e/97htbcvedprq', 'https://drive.google.com/file/d/1polsvuQiOWLuwMbam1E470JFtZUkCh1p/view?usp=drive_link', '2026-04-04 08:51:37', '69d0b4f90b365092796', 7),
(3844, 2104, '69d0fff8b0b66092850', 'Young Sherlock Ep1', '1 The Case of the Missing Scrolls', '1871. A wayward young Sherlock Holmes is sent to Oxford to keep out of trouble, but he soon finds himself the prime suspect in a police investigation that threatens his entire future.', 'Action', '66', 'https://bysetayico.com/e/kbiyvghbf9fq', 'https://drive.google.com/file/d/15b8wRHji3vBaax0rG3GAJcX72YfVcMkC/view?usp=drive_link', '2026-04-04 14:21:59', '69d10267508b4988290', 3),
(3845, 2104, '69d0fff8b0b66092850', 'Young Sherlock Ep2', '2 The Case of the Burnt Photograph', 'Sherlock is thrown into jail. He has to clear his name or face the gallows.', 'Action', '54', 'https://bysetayico.com/e/y8rm72pnmfwi', 'https://drive.google.com/file/d/1c5lLsTxjbjgy1SZVKfR2xLN_2sTNKS9j/view?usp=drive_link', '2026-04-04 14:22:33', '69d10289a28f0632406', 1),
(3846, 2104, '69d0fff8b0b66092850', 'Young Sherlock Ep3', '3 The Case of the Unarmed Man', 'The game\'s afoot. With another murder and two professors missing, it\'s a race against time for Sherlock and Moriarty to find them before the killer does.', 'Action', '55', 'https://bysetayico.com/e/1itux1sd7arv', 'https://drive.google.com/file/d/1JOX7C8chIZ_V4NJWy5Cdx1JLeI38HNno/view?usp=drive_link', '2026-04-04 14:23:19', '69d102b75203f121344', 2),
(3847, 2104, '69d0fff8b0b66092850', 'Young Sherlock Ep4', '4 The Case of the Missing Button', 'Sherlock returns to his childhood home in search of answers.', 'Action', '61', 'https://bysetayico.com/e/d7pmgw435iie', 'https://drive.google.com/file/d/1VMgEicPsLKthYjPSBKsy_SFEr-EFzbIA/view?usp=drive_link', '2026-04-04 14:23:52', '69d102d84e6a8892109', 1);
