(3848, 2104, '69d0fff8b0b66092850', 'Young Sherlock Ep5', '5 The Case of Young Sherlock Holmes', 'Years after a tragic accident that tore the Holmes family apart, Moriarty and Sherlock come to blows as they investigate that fateful day.', 'Action', '59', 'https://bysetayico.com/e/xhia92gevrnv', 'https://drive.google.com/file/d/1CXZW4dFrjuU29EO-UTtzXlFe5iGrybY7/view?usp=drive_link', '2026-04-04 14:24:30', '69d102fea748e942802', 1),
(3849, 2104, '69d0fff8b0b66092850', 'Young Sherlock Ep6', '6 The Case of the Killing Jar', 'As Sherlock digs deeper into the Oxford murders, he discovers a shocking connection.', 'Action', '58', 'https://bysetayico.com/e/pf5m7leag8ke', 'https://drive.google.com/file/d/1wsshobxYoCeMNSR8nsIBYcLzfHxs_-MS/view?usp=drive_link', '2026-04-04 14:25:15', '69d1032b4f6cc220233', 1),
(3850, 2104, '69d0fff8b0b66092850', 'Young Sherlock Ep7', '7 The Case of the Two Corners', 'An impossible ultimatum challenges Sherlock\'s loyalties.', 'Action', '59', 'https://bysetayico.com/e/6g6s9x9hd667', 'https://drive.google.com/file/d/1DKk0-wn4FG1q8VEPLeMQRvZg83RKzYKD/view?usp=drive_link', '2026-04-04 14:25:56', '69d103549c34a243718', 1),
(3851, 2103, '69d0b394734db534669', 'Taken Ep4', '4 Mattie G.', 'Riley\'s insistence to uncover the truth behind a fatal drug given to war vets results in her asset\'s child being taken. Bryan defies orders to rescue the girl and uncover the truth. When a break-in at Asha\'s apartment leaves her shaken, a new neighbor is there to calm her nerves.', 'Action', '42', 'https://bysetayico.com/e/60ve074vto38', 'https://drive.google.com/file/d/1LGAsB2WYQ6scXulx0g_5Io7NEHMgxcj6/view?usp=drive_link', '2026-04-08 11:42:54', '69d6231eb1e87866457', 1),
(3852, 2103, '69d0b394734db534669', 'Taken Ep5', '5 A Clockwork Swiss', 'Christina orders the retrieval of sensitive documents in Zurich needed to prevent economic and political disaster. But the mission to break into a bank vault turns into a three-way battle, and a race to escape safely. Meanwhile, Asha\'s trust in Elena proves to be misplaced and leaves Bryan vulnerable.', 'Action', '43', 'https://bysetayico.com/e/16vcs02zwd2q', 'https://drive.google.com/file/d/1SicmVIn5BX2uDHZcjTIVa9yunT1SfIMg/view?usp=drive_link', '2026-04-08 11:43:44', '69d6235028a49714880', 2),
(3853, 2103, '69d0b394734db534669', 'Taken Ep6', '6 Hail Mary', 'The ODNI is asked to facilitate the defection of a Russian FSB agent, but the agent\'s pregnant girlfriend throws a curve in the team\'s plans. Meanwhile, Christina goes off the books to reveal a mole in the CIA, and John\'s attempt to resolve his brother\'s problem with a local gang results in a spiritual crisis.', 'Action', '49', 'https://bysetayico.com/e/ccrsz21wy5cp', 'https://drive.google.com/file/d/1xW_Pbp5XXqQC9ye4psNxT8K5cZFRYPKb/view?usp=drive_link', '2026-04-08 11:44:26', '69d6237aa4bc8619117', 2),
(3854, 2105, '69d62490a4673711192', 'La Brea Ep1', '1 Pilot', 'When a massive sinkhole opens in Los Angeles, the Harris family is split in two. Eve and her son are sent to a mysterious primeval world. Gavin discovers that the visions that have plagued him for years might hold the key to bringing them home.', 'Sci-Fi', '47', 'https://bysetayico.com/e/tohhsc0z75vi', 'https://drive.google.com/file/d/1gtbRncVh0l_dgvq4ehrKQnCCM_YbTqhU/view?usp=drive_link', '2026-04-08 11:52:23', '69d62557e7505146103', 3),
(3855, 2105, '69d62490a4673711192', 'La Brea Ep2', '2 Day Two', 'With Joshâ€™s life on the line, Eve traverses the dangerous wilderness back to the clearing to save him. Desperate to kickstart a rescue mission, Gavin and Izzy work to prove there are survivors alive inside the sinkhole as government agents track their every move.', 'Sci-Fi', '59', 'https://bysetayico.com/e/k5jnne7mfqg4', 'https://drive.google.com/file/d/1z5fY3YTFsgV9jZiT9vUNNKeuxKwJ4UH1/view?usp=drive_link', '2026-04-08 11:52:59', '69d6257b90c96903419', 2),
(3856, 2105, '69d62490a4673711192', 'La Brea Ep3', '3 The Hunt', 'With the survivorsâ€™ food supply dwindling, Eve and Ty venture into the forest on a risky hunting expedition only to face unexpected dangers that threaten their survival. As an unlikely rescue mission comes to fruition, Gavin must put his faith â€“ and the fate of his family â€“ in the hands of an old friend with whom he shares a complicated past.', 'Sci-Fi', '57', 'https://bysetayico.com/e/f3ivg2illh3q', 'https://drive.google.com/file/d/1juMLFYznt9BzPYGfgiGviy1an-l8cIFs/view?usp=drive_link', '2026-04-08 11:53:41', '69d625a579ce8030058', 2),
(3857, 2103, '69d0b394734db534669', 'Taken Ep7', '7 Solo', 'During the team\'s efforts to thwart a Mejia weapons operation, Bryan is taken. As he relies on his ODNI training to survive, the team attempts a daring rescue. Meanwhile, Bryan and Asha take their relationship to the next level.', 'Action', '44', 'https://bysetayico.com/e/suknw10x7ai9', 'https://drive.google.com/file/d/1MBua9CQ8YOhcPtr6hFUcVe2egxGxN6xM/view?usp=drive_link', '2026-04-08 21:17:36', '69d6a9d01c858215601', 2);
