(1220, 'Eye for an Eye 1', 'A highly trained and exceptionally deadly swordsman looks for revenge after being caught in the middle of a power struggle that results in the assassination of an innocent woman\'s family.', 'Action', 2022, '83', 'B The Great', 'https://bysetayico.com/e/9vma6ny7sqs2', 'https://drive.google.com/file/d/1Smwu6Za4fhm3BRJ9ajBt_S-rcOu1F99a/view?usp=drive_link', 'https://media.theonemovies.com/eye-for-an-eye-7655.jpg', 'No', 'zQ5SEiBYmp', '2026-01-23 07:57:08', '69730db4c3117719041', '7.3', 6, NULL),
(1221, 'Eye for an Eye 2', 'The blind swordsman, skilled in martial arts, named Cheng Xiazi (Xie Miao), accidentally saves Zhang Xiaoyu (Yang Enyou), who has suffered from the destruction of his family. Under the persuasion of the orphan Xiaoyu, Cheng reluctantly keeps him by his side and teaches him skills. Xiaoyu also waits for the opportunity to seek revenge.', 'Action', 2024, '91', 'B The Great', 'https://bysetayico.com/e/b38p0ck9pkbp', 'https://drive.google.com/file/d/1_9ashl1LMVGf0d21u16dcpLc6BHI6vVt/view?usp=drive_link', 'https://media.theonemovies.com/eye-for-an-eye-2-7455.jpg', 'No', 'oFrhRwgfRE', '2026-01-23 08:00:43', '69730e8b8ca36055347', '6.4', 8, NULL),
(1222, 'Barren Land A', 'Barren Land is the story of three friends. All three trapped between the abandonment of the institutions, the violent and unstoppable rise of the narco in the province and the dangerous increase of social discontent. Three friends trapped in a powder keg that will test their friendship.', 'Action', 2025, '54', 'Mr Fire', 'https://bysetayico.com/e/d5prb2pgadf2', 'https://drive.google.com/file/d/1dlSq3L8S6x8UJXRKRqf04_fvVyw7Iu6v/view?usp=drive_link', 'https://media.theonemovies.com/barren-land-a-5893.jpg', 'No', '1KYlDQtnDc', '2026-01-24 09:32:51', '697475a3ed2f8448441', '6.3', 12, NULL),
(1223, 'Barren Land B', 'Barren Land is the story of three friends. All three trapped between the abandonment of the institutions, the violent and unstoppable rise of the narco in the province and the dangerous increase of social discontent. Three friends trapped in a powder keg that will test their friendship.', 'Action', 2025, '47', 'Mr Fire', 'https://bysetayico.com/e/aoxyqxcvaw5a', 'https://drive.google.com/file/d/13lWyoqUDmwahky1aUSW7v4JGp8JEJtfF/view?usp=drive_link', 'https://media.theonemovies.com/barren-land-b-3811.jpg', 'Yes', '1KYlDQtnDc', '2026-01-24 09:34:51', '6974761b624de409947', '6.3', 0, NULL),
(1224, 'Cruel War', 'Yan Xin, a female scientist at Hainan Xingye Torch Company, used gene editing technology to cultivate super rubber seeds and went to Yinfan Island overseas for trial planting, hoping to turn it into a rich new world. Lin Xiang of the International Security Company personally led the team to this crisis-ridden land in order to protect his still beloved ex-wife Yan Xin. Since their arrival, conflicts and conspiracies have been taking turns, with the figure of local drug lord Li Wenyao looming behind them. Unknown dangers, the ultimate showdown, the two people opposing good and evil cannot escape the destined battle.', 'Action', 2024, '104', 'Sankara', 'https://bysetayico.com/e/wzzu9h5l7kxq', 'https://drive.google.com/file/d/1YiEfkVTxTj4faZOBJB_8V5VYYFFr-9RC/view?usp=drive_link', 'https://media.theonemovies.com/cruel-war-4032.jpg', 'No', 'gbrIFOYrr4', '2026-01-25 13:19:38', '6975fc4a364e7609362', '7', 9, NULL),
