(1226, 'Assassin Club', 'In this world of contract killers, Morgan Gaines is the best of the best. When Morgan is hired to kill six people around the world, he soon discovers all the targets are also assassins unknowingly hired to kill each other.', 'Action', 2023, '128', 'Sankara', 'https://bysetayico.com/e/yr3ksb5ubj1i/assassin-club', 'https://drive.google.com/file/d/1OKnSEJEj0C8g62O5MvD__Hc5Diljrci8/view?usp=drive_link', 'https://media.theonemovies.com/assassin-club-6092.jpg', 'No', '72EP2LJT8x', '2026-01-25 19:38:39', '6976551f95fdd666513', '5.9', 8, NULL),
(1227, 'Icefall', 'A young Indigenous game warden arrests an infamous poacher only to discover that the poacher knows the location of a plane carrying millions of dollars that has crashed in a frozen lake. When a group of criminals and dirty cops are alerted to the poacherâ€™s whereabouts, the warden and the poacher team up to fight back and escape across the treacherous lake before the ice melts.', 'Action', 2025, '85', 'Sankara', 'https://bysetayico.com/e/zzy9hvcithy8', 'https://drive.google.com/file/d/12gYHtUjg7_z9X-f8ppiC-euLOP1esaSS/view?usp=drive_link', 'https://media.theonemovies.com/icefall-8454.jpg', 'No', 'RvsqUt5L54', '2026-01-27 17:52:31', '6978df3fc5f4e270691', '6.5', 13, NULL),
