(1229, 'Greenland 2: Migration A', 'Having found the safety of the Greenland bunker after the comet Clarke decimated the Earth, the Garrity family must now risk everything to embark on a perilous journey across the wasteland of Europe to find a new home.', 'Sci-Fi', 2026, '49', 'Hakim', 'https://bysetayico.com/e/lw2q6bfdjt1l', 'https://drive.google.com/file/d/1zqab5eiimH0JBzvRLRke4KtWeuM8sdc1/view?usp=drive_link', 'https://media.theonemovies.com/greenland-2-migration-a-2476.jpg', 'No', '4gfM3GyJfb', '2026-01-28 23:21:09', '697a7dc5e4d26287032', '6.6', 8, NULL),
(1230, 'Greenland 2: Migration B', 'Having found the safety of the Greenland bunker after the comet Clarke decimated the Earth, the Garrity family must now risk everything to embark on a perilous journey across the wasteland of Europe to find a new home.', 'Sci-Fi', 2026, '44', 'Hakim', 'https://bysetayico.com/e/w9l29txhs6l5', 'https://drive.google.com/file/d/1rdWOGNti7RaTDN9D0Vg-1kJm-3J2ghLL/view?usp=drive_link', 'https://media.theonemovies.com/greenland-2-migration-b-1134.jpg', 'Yes', '4gfM3GyJfb', '2026-01-28 23:22:35', '697a7e1bd37ce441535', '6.6', 1, NULL),
(1231, 'The Wrecking Crew', 'Estranged half-brothers Jonny and James reunite after their father\'s mysterious death. As they search for the truth, buried secrets reveal a conspiracy threatening to tear their family apart.', 'Action', 2026, '120', 'Hakim', 'https://bysetayico.com/e/cjkl4rfs8n9v', 'https://drive.google.com/file/d/1z2WHJIXjq8Dg6XrsYR2oggcy4W6FPzIl/view?usp=drive_link', 'https://media.theonemovies.com/the-wrecking-crew-7265.jpg', 'No', '7m2gOCL5Lb', '2026-01-28 23:24:52', '697a7ea4c5306511348', '6.9', 14, NULL),
(1232, 'Project Wolf Hunting A', 'While under heavily armed guard, the dangerous convicts aboard a cargo ship unite in a coordinated escape attempt that soon escalates into a bloody, all-out riot. But as the fugitives continue their brutal campaign of terror, they soon discover that not even the most vicious among them is safe from the horror they unknowingly unleashed from the darkness below deck.', 'Horror', 2022, '62', 'Mr Fire', 'https://bysetayico.com/e/fmj6orwsbo0l', 'https://drive.google.com/file/d/19pFw8kye3LozLRxVt6qpjSAivU6joF3C/view?usp=drive_link', 'https://media.theonemovies.com/project-wolf-hunting-a-7582.jpg', 'No', 'iRtHziHM39', '2026-01-29 20:46:21', '697baafdc7786253998', '6.4', 7, NULL),
