(1234, 'Awareness', 'Ian is a teenager who lives with his father on the outskirts by running small scams using Ian\'s ability to generate visual illusions upon unsuspecting victims. When one of his cons goes awry, his abilities publicly spiral out of control and Ian becomes the target of two rival organizations, each seeking to exploit his powers.', 'Sci-Fi', 2023, '117', 'Mr Fire', 'https://drive.google.com/file/d/1c9B7MesJyg1rnfhMYA3HoLfUt0CDefFe/view?usp=drive_link', '', 'https://media.theonemovies.com/awareness-9403.jpg', 'No', 'rrIVLETyuw', '2026-01-30 21:55:53', '697d0cc9e53a5019375', '5.9', 3, NULL),
(1235, 'They Call Him OG A', 'After vanishing from Mumbai\'s underworld for a decade, mob boss Ojas Gambheera resurfacesâ€”feared, unstoppable, and with a single goal: to reclaim his empire and exact vengeance on the current tyrant, Omi Bhau. As loyalties fracture and alliances shift, OG reignites a brutal criminal war, confronting both external threats and haunting buried betrayals.', 'Indian', 2025, '84', 'B The Great', 'https://bysetayico.com/e/fpqzz5vexp72', 'https://drive.google.com/file/d/1rm4-yQj1NzoBYyvrRYH3q2Al-36f5vHk/view?usp=drive_link', 'https://media.theonemovies.com/ojas-ghambheera-a-4531.jpg', 'No', 'wtYAMQqeZ5', '2026-01-30 22:06:39', '697d0f4fbef43717633', '6.2', 3, NULL);
