(1237, 'Anaconda', 'A group of friends facing mid-life crises head to the rainforest with the intention of remaking their favorite movie from their youth, only to find themselves in a fight for their lives against natural disasters, giant snakes and violent criminals.', 'Horror', 2025, '112', 'Gaheza', 'https://bysetayico.com/e/2nirqc9fudeo', 'https://drive.google.com/file/d/1VYOsVfYCM-RjHzdntjU2QUk_w554JcLA/view?usp=drive_link', 'https://media.theonemovies.com/anaconda-2348.jpg', 'No', 'KUJPVFfaKm', '2026-01-31 07:47:38', '697d977adaf12281171', '6', 13, NULL),
(1238, 'Altered', 'In an alternate present, genetically enhanced humans dominate society. Outcasts Leon and Chloe fight for justice against corrupt politicians exploiting genetic disparity, risking everything to challenge the oppressive system.', 'Sci-Fi', 2025, '89', 'Mungeli', 'https://drive.google.com/file/d/1qYJpIPpJFTqq3YMXHapb7WegmvlbQ8vU/view?usp=drive_link', '', 'https://media.theonemovies.com/altered-3141.jpg', 'No', 'snDhOjSE99', '2026-01-31 08:52:20', '697da6a49cea5638788', '6', 9, NULL),
(1239, 'American Sniper', 'U.S. Navy SEAL Chris Kyle takes his sole missionâ€”protect his comradesâ€”to heart and becomes one of the most lethal snipers in American history. His pinpoint accuracy not only saves countless lives but also makes him a prime target of insurgents. Despite grave danger and his struggle to be a good husband and father to his family back in the States, Kyle serves four tours of duty in Iraq. However, when he finally returns home, he finds that he cannot leave the war behind.', 'Action', 2014, '128', 'Cyber', 'https://bysetayico.com/e/sr1yre6bjjtl', 'https://drive.google.com/file/d/1U5A8MLrfxrZAdgEX_nBS_gYqPSqZ4z83/view?usp=drive_link', 'https://media.theonemovies.com/american-sniper-1832.jpg', 'No', '41mME5MsXw', '2026-01-31 13:25:39', '697de6b3544b2603231', '7.4', 2, NULL),
(1240, 'Darc', 'To bring down a global human trafficking ring, an Interpol agent recruits the help of a brutal criminal with inside knowledge of the yakuza.', 'Action', 2018, '95', 'Cyber', 'https://bysetayico.com/e/0lyrpwpy5vpr', 'https://drive.google.com/file/d/1X1iMnlyZ-VZSvgKhmCR76ibdUnsRAPDz/view?usp=drive_link', 'https://media.theonemovies.com/darc-5811.jpg', 'No', 'oYR6dyQw9J', '2026-01-31 13:27:53', '697de73951f93054600', '6.1', 5, NULL),
(1241, 'WarHunt', '1945. A U.S. military cargo plane loses control and violently crashes behind enemy lines in the middle of the German black forest. Major Johnson sends a squad of his bravest soldiers on a rescue mission to retrieve the top-secret material the plane was carrying, led by Sergeants Brewer and Walsh. They soon discover hanged Nazi soldiers and other dead bodies bearing ancient, magical symbols. Suddenly their compasses fail, their perceptions twist and straying from the group leads to profound horrors as they are attacked by a powerful, supernatural force.', 'Action', 2022, '90', 'Cyber', 'https://bysetayico.com/e/l5uz07d5zuf5', 'https://drive.google.com/file/d/1fUD084vrPZkfpRl6_S3UoYWj5Hg_pFOs/view?usp=drive_link', 'https://media.theonemovies.com/warhunt-3748.jpg', 'No', 'xpz4nX1EXt', '2026-01-31 13:30:02', '697de7ba5961d006493', '5', 5, NULL),
(1242, 'The Running Man', 'Desperate to save his sick daughter, working-class Ben Richards is convinced by The Running Man\'s charming but ruthless producer to enter the deadly competition game as a last resort. But Ben\'s defiance, instincts, and grit turn him into an unexpected fan favorite â€” and a threat to the entire system. As ratings skyrocket, so does the danger, and Ben must outwit not just the Hunters, but a nation addicted to watching him fall.', 'Action', 2025, '163', 'Gaheza', 'https://drive.google.com/file/d/1b090yDppgxpIrXcfLPzoVs7LBJaoySNb/view?usp=drive_link', 'https://drive.google.com/file/d/1b090yDppgxpIrXcfLPzoVs7LBJaoySNb/view?usp=drive_link', 'https://media.theonemovies.com/the-running-man-4924.jpg', 'No', 'MFkU9IBZvb', '2026-02-06 18:48:49', '697de859ad32d282572', '6.8', 25, NULL),
