(1316, 'One Mile: Chapter Two B', '<b>| 02/20/2026 (US) Action and Crime.</b><br>\r\nFormer special forces operative Danny is forced back onto a remote island when a violent, secretive community takes revenge by abducting his daughter Alex, launching a relentless hunt against enemies prepared for his every move.', 'Action', 2026, '32', 'Mr Fire', 'https://bysetayico.com/e/ucfnirf0zdxc', 'https://drive.google.com/file/d/1kGyhrMwGWUD2_fwrY_JppMV277RsHoCi/view?usp=drive_link', 'https://media.theonemovies.com/one-mile-chapter-two-b-4353.jpg', 'Yes', '81ztD0gaij', '2026-02-23 13:01:59', '699c33a7d06bc899843', '8', 1, NULL),
