(1318, 'Aftermath', '<b>| 11/01/2024 (US) - Action and Thriller.</b><br>\r\nA returning war veteran, stricken with PTSD, gets trapped with his teenage sister on Boston\'s Tobin Memorial Bridge when a heavily armed group of ex-military revolutionaries take everyone hostage.', 'Action', 2024, '118', 'Junior Giti', 'https://drive.google.com/file/d/1tSN_TgvLQkfCwM5A1YnQxTupzPiFIuD8/view?usp=drive_link', 'https://drive.google.com/file/d/1tSN_TgvLQkfCwM5A1YnQxTupzPiFIuD8/view?usp=drive_link', 'https://media.theonemovies.com/aftermath-1984.jpg', 'No', 'Epv4qhunjb', '2026-02-24 23:21:54', '699e1672aeb79557794', '6.2', 11, NULL),
(1319, 'The Mercenary', '<b>| 01/07/2020 (US) - Action.</b><br>\r\nWhen a mission in South America goes wrong a mercenary is left for dead, but he is nursed back to health and reborn with a new outlook on life. But his peaceful days are short-lived when mercenaries he used to work with cross his path again and he is forced to revisit and face his own demons.', 'Action', 2020, '87', 'Junior Giti', 'https://bysetayico.com/e/tqalwdj1utcv', 'https://drive.google.com/file/d/18e_BMqkk7-thnGbnkS4CQD37prlCjUfO/view?usp=drive_link', 'https://media.theonemovies.com/the-mercenary-3202.jpg', 'No', 'VPb93zr9Ca', '2026-02-24 23:24:53', '699e172582707606260', '6', 10, NULL),
(1320, 'Zootopia 2', '<b>| 11/26/2025 (US) - Animation, Comedy, Adventure, Family, and Mystery.</b><br>\r\nAfter cracking the biggest case in Zootopia\'s history, rookie cops Judy Hopps and Nick Wilde find themselves on the twisting trail of a great mystery when Gary De\'Snake arrives and turns the animal metropolis upside down. To crack the case, Judy and Nick must go undercover to unexpected new parts of town, where their growing partnership is tested like never before.', 'Animation', 2025, '98', 'Master P', 'https://bysetayico.com/e/wl92nclhrlig', 'https://drive.google.com/file/d/1--Dm8-Is9Tisi1SZml8RCWQgMbH9wxyB/view?usp=drive_link', 'https://media.theonemovies.com/zootopia-2-2267.jpg', 'No', 'gqOin02n6x', '2026-02-24 23:27:52', '699e17d8bca7e199734', '7.6', 9, NULL),
(1321, 'The Gorge', '<b>| 02/13/2025 (US) - Romance, Science Fiction, and Thriller.</b><br>\r\nTwo highly trained operatives grow close from a distance after being sent to guard opposite sides of a mysterious gorge. When an evil below emerges, they must work together to survive what lies within.', 'Romance', 2025, '135', 'Gaheza', 'https://bysetayico.com/e/dd2j18d2melk', 'https://drive.google.com/file/d/1cJzrs4Sn_ZwMQY4nb5HqvjSU9B_1HfiJ/view?usp=drive_link', 'https://media.theonemovies.com/the-gorge-5547.jpg', 'No', 'eWDfgcV75I', '2026-02-25 13:21:55', '699edb53f013d717364', '7.6', 5, NULL),
(1322, '11 Rebels', '<b>| 11/01/2024 (JP) - Action, Drama, History, and Thriller.</b><br>\r\nWhen the brutal Boshin War breaks out in Japan, a group of inmates on death row unite to defend a fortress against the Imperial army.', 'Action', 2024, '157', 'Mungeli', 'https://bysetayico.com/e/6a0ffnceq2r4', 'https://drive.google.com/file/d/1pZhK9Tx023X_W-I_u5-JQCOc45Vcr3W2/view?usp=drive_link', 'https://media.theonemovies.com/11-rebels-4038.jpg', 'No', '1Zbo46bZBM', '2026-02-25 13:25:38', '699edc32d1916918645', '7.1', 4, NULL),
(1323, 'Mercy', '<b>| 01/23/2026 (US) - Science Fiction, Action, and Thriller.</b><br>\r\nIn the near future, a detective stands on trial accused of murdering his wife. He has ninety minutes to prove his innocence to the advanced AI Judge he once championed, before it determines his fate.', 'Sci-Fi', 2026, '92', 'Hakim', 'https://bysetayico.com/e/7t6u91p5j2hx', 'https://drive.google.com/file/d/1YVpssNP-7MxmGNKb_2IOyay0HEYeuVLV/view?usp=drive_link', 'https://media.theonemovies.com/mercy-8086.jpg', 'No', '4LWzvSYQQV', '2026-02-25 17:05:31', '699f0fbb9e468448370', '7.1', 8, NULL),
