(1330, 'Sniper: The Last Stand', '<b>| 01/21/2025 (US) - Action and Thriller.</b><br>\r\nTo stop an arms dealer from unleashing a deadly superweapon, Ace sniper Brandon Beckett and Agent Zero are deployed to Costa Verde to lead a group of elite soldiers against an unrelenting militia. Taking an untested sniper under his wing, Beckett faces his newest challenge: giving orders instead of receiving them. With both time and ammo running low in a race to save humanity, the team must overcome all odds just to survive.', 'Action', 2025, '129', 'Gaheza', 'https://bysetayico.com/e/5hhl5ysdbbb5', 'https://drive.google.com/file/d/1oz29DivYuTwZkdi_xOrKN21hBxxMwBYm/view?usp=drive_link', 'https://media.theonemovies.com/sniper-the-last-stand-9572.jpg', 'No', 'V4wC2kHvzZ', '2026-02-26 22:14:46', '69a0a9b602bc9570789', '6.8', 5, NULL),
(1331, 'A Good Man', '<b>| 04/13/2023 (US) - Drama and Thriller.</b><br>\r\nStruggling in the aftermath of his wife\'s affair, a man\'s attempt at a new relationship begins to spiral out of control when he notices familiar signs.', 'Drama', 2023, '102', 'Sankara', 'https://bysetayico.com/e/fe2dhbq4isia', 'https://drive.google.com/file/d/12GZuEy8IXxXFvZrEql5s_BrYyb2Gc3V1/view?usp=drive_link', 'https://media.theonemovies.com/a-good-man-8674.jpg', 'No', 'grPHjAaUCc', '2026-02-27 13:14:00', '69a17c783af28852739', '5', 13, NULL),
(1332, 'Jigsaw', '<b>| 10/27/2017 (US) - Horror and Mystery.</b><br>\r\nLaw enforcement finds itself chasing the ghost of a man dead for over a decade, embroiled in a diabolical new game that\'s only just begun.', 'Horror', 2017, '97', 'Sankara', 'https://bysetayico.com/e/centlay8mhpl', 'https://drive.google.com/file/d/1iTCgCl4-p4t6BYFWZ7VzAFU4QNK2GhcF/view?usp=drive_link', 'https://media.theonemovies.com/jigsaw-2731.jpg', 'No', 'Lcz1s7LLWW', '2026-02-27 13:15:50', '69a17ce6bc1c5409186', '6.2', 3, NULL),
(1333, 'The Bluff', '<b>| 02/17/2026 (US) - Action and Thriller.</b><br>\r\nWhen her tranquil life on a remote island is shattered by the return of her vengeful former captain, a skilled ex-pirate must confront her bloody past and unleash her deadly talents to save her family from a ruthless siege.', 'Action', 2026, '96', 'Hakim', 'https://drive.google.com/file/d/1JzVPea1xVMCcR5GU1JfSAVlmq4Z4KcyI/view?usp=drive_link', 'https://drive.google.com/file/d/1JzVPea1xVMCcR5GU1JfSAVlmq4Z4KcyI/view?usp=drive_link', 'https://media.theonemovies.com/the-bluff-9664.jpg', 'No', 'DRvOxf8aB7', '2026-02-27 22:00:25', '69a1f7d9a544f109166', '6.1', 10, NULL),
(1334, 'Reckless', '<b>| 02/07/2026 (GB) - Action, Comedy, Crime, and Thriller.</b><br>\r\nA former convict on parole must outwit the police to get his share of an old heist.', 'Action', 2026, '79', 'Hakim', 'https://drive.google.com/file/d/1S5P3w4JRGYmmVZAU4KQ38hvU_cdK-vEz/view?usp=drive_link', '', 'https://media.theonemovies.com/reckless-6427.jpg', 'No', 'hvyg5U4Qo6', '2026-02-28 12:12:04', '69a2bf746c756908689', '6.2', 3, NULL),
(1335, 'Iron Sky: The Coming Race', '<b>| 01/16/2019 (FI) - Action, Comedy, Fantasy, and Science Fiction.</b><br>\r\n29 years after the events of Iron Sky, the former Nazi Moonbase has become the last refuge of mankind. Earth was devastated by a nuclear war, but buried deep under the wasteland lies a power that could save the last of humanity - or destroy it once and for all. An old enemy leads our heroes on an adventure into the Hollow Earth. To save humanity, they must battle the Vril, an ancient shapeshifting reptilian race, and their army of dinosaurs.', 'Action', 2019, '72', 'PK', 'https://drive.google.com/file/d/1i7bcAtkUYFpIwEQMA7OaZKkq3VrkNIoK/view?usp=drive_link', '', 'https://media.theonemovies.com/iron-sky-the-coming-race-9270.jpg', 'No', '5BkDNkLV4m', '2026-02-28 22:04:03', '69a34a330f6d4652062', '5.2', 8, NULL),
(1336, 'Agent Zero', '<b>| 08/06/2025 (FR) - Action and Thriller.</b><br>\r\nWhen police officer Ilias is shot and left in a coma, Alma must reconnect with her former identity as Badh, a ruthless intelligence operative and skilled assassin. She brutally eliminates members of the Khoury family one by one, unleashing the fury of their leader Mansour, only to discover that Mansour is working with Joana, her former secret service unit officer.', 'Action', 2025, '78', 'Mr Fire', 'https://bysetayico.com/e/w9qqzwd3r6p1', 'https://drive.google.com/file/d/1Iuai3O-P8SQwdGfOAWx0_YT6Ti_6f1UI/view?usp=drive_link', 'https://media.theonemovies.com/agent-zero-6508.jpg', 'No', 'QDGWauZzhL', '2026-03-01 22:25:00', '69a4a09cf00bf975766', '5.4', 9, NULL),
