(2012, 'Squid Game S1', 'Hundreds of cash-strapped players accept a strange invitation to compete in children\'s games. Inside, a tempting prize awaits â€” with deadly high stakes.', 'Action', 2021, 'Rocky', 1, 9, '1758464784.jpg', '2025-08-20 15:45:43', '68a5d187c5', '7.9', 5, NULL),
